import { Component, OnInit, OnDestroy, inject, ChangeDetectorRef } from '@angular/core';
import { FormBuilder, FormGroup, ReactiveFormsModule } from '@angular/forms';
import { CommonModule } from '@angular/common';
import { LucideAngularModule } from 'lucide-angular';
import { Subject, takeUntil } from 'rxjs';

import { AuthService } from '../../services/Base/auth.service';
import { SupabaseService } from '../../services/Base/supabase.service';
import { GeographyService } from '../../services/Base/geography.service';
import { TutorialService, TutorialType } from '../../services/tutorial.service';
import { PushNotificationService } from '../../services/push-notification.service';

interface UserProfile {
  id: string;
  email: string;
  first_name: string;
  last_name: string;
  phone: string | null;
  province?: string | null;
  address?: string | null;
  avatar_url: string | null;
  preferences: any;
  is_active: boolean;
}

@Component({
  selector: 'app-profile-user',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, LucideAngularModule],
  templateUrl: './profile-user.html',
  styleUrls: ['./profile-user.css']
})
export class ProfileUser implements OnInit, OnDestroy {
  private fb = inject(FormBuilder);
  private authService = inject(AuthService);
  private supabaseService = inject(SupabaseService);
  private tutorialService = inject(TutorialService);
  private geographyService = inject(GeographyService);
  private cdRef = inject(ChangeDetectorRef);
  public pushService = inject(PushNotificationService);

  pushPermission: NotificationPermission | 'unsupported' = 'default';
  hasActivePush  = false;
  pushLoading    = false;

  private destroy$ = new Subject<void>();
  private supabaseClient = this.supabaseService.getSupabaseClient();

  profileForm!: FormGroup;
  loading = false;
  userProfile?: UserProfile;

  // Province e regioni
  provinces: any[] = [];
  regions: string[] = [];
  filteredProvinces: any[] = [];
  selectedProvinceName: string = '';

  ngOnInit(): void {
this.pushPermission = this.pushService.isSupported()
  ? Notification.permission
  : 'unsupported';
this.pushService.hasActiveSubscription().then(v => this.hasActivePush = v);

    this.initForm();
    this.loadProvinces();
    this.loadUserProfile();
  }

  ngOnDestroy(): void {
    this.destroy$.next();
    this.destroy$.complete();
  }

  private initForm(): void {
    this.profileForm = this.fb.group({
      phone: [''],
      address: [''],
      region: [''],
      province: ['']
    });
  }

  private async loadProvinces(): Promise<void> {
    this.geographyService.getFilteredProvinces()
      .pipe(takeUntil(this.destroy$))
      .subscribe({
        next: (provinces) => {
          this.provinces = provinces;
          this.regions = [...new Set(provinces.map(p => p.region))]
            .filter(region => region !== 'Tutte')
            .sort();

          const currentRegion = this.profileForm.get('region')?.value;
          if (currentRegion) {
            this.filterProvincesByRegion(currentRegion);
          }
          this.cdRef.detectChanges();
        },
        error: (err) => console.error('Errore caricamento province:', err)
      });
  }

  private filterProvincesByRegion(region: string): void {
    this.filteredProvinces = region
      ? this.provinces.filter(p => p.region === region)
      : [];

    if (!region) {
      this.profileForm.patchValue({ province: '' });
    }
  }

  onRegionChange(event: Event): void {
    const select = event.target as HTMLSelectElement;
    const region = select.value;
    this.filterProvincesByRegion(region);
  }

  onProvinceChange(event: Event): void {
    const select = event.target as HTMLSelectElement;
    const provinceCode = select.value;
    const province = this.provinces.find(p => p.code === provinceCode);
    this.selectedProvinceName = province ? province.name : '';
  }

  private async loadUserProfile(): Promise<void> {
    this.loading = true;
    try {
      const user = this.authService.currentUserValue;
      if (!user) throw new Error('Utente non autenticato');

      const { data: userData, error } = await this.supabaseClient
        .from('users')
        .select('*')
        .eq('id', user.id)
        .single();

      if (error) {
        if (error.code === 'PGRST116') {
          // Profilo non esiste, lo creiamo
          await this.createUserProfile(user.id);
          return;
        }
        throw error;
      }

      if (userData) {
        this.userProfile = userData;
        this.patchForm(userData);
      }
    } catch (err: any) {
      console.error('Errore caricamento profilo:', err);
    } finally {
      this.loading = false;
      this.cdRef.detectChanges();
    }
  }

  private async createUserProfile(userId: string): Promise<void> {
    const user = this.authService.currentUserValue;
    if (!user) return;

    const userPayload = {
      id: userId,
      email: user.email,
      first_name: user.first_name || '',
      last_name: user.last_name || '',
      phone: null,
      address: null,
      avatar_url: null,
      preferences: {
        email_notifications: true,
        newsletter: true
      },
      is_active: true,
      role: 'customer',
      created_at: new Date().toISOString(),
      updated_at: new Date().toISOString()
    };

    const { data, error } = await this.supabaseClient
      .from('users')
      .insert(userPayload)
      .select()
      .single();

    if (error) {
      console.error('Errore creazione profilo:', error);
      return;
    }

    if (data) {
      this.userProfile = data;
      this.patchForm(data);
    }
  }

  private patchForm(data: UserProfile): void {
    // Determina la regione in base alla provincia salvata
    let regionToSet = '';
    if (data.province) {
      const savedProvince = this.provinces.find(p => p.code === data.province);
      if (savedProvince) {
        regionToSet = savedProvince.region;
        this.filterProvincesByRegion(regionToSet);
      }
    }

    this.profileForm.patchValue({
      phone: data.phone || '',
      address: data.address || '',
      region: regionToSet,
      province: data.province || ''
    });
  }

  async onSubmit(): Promise<void> {
    if (this.profileForm.invalid) return;

    this.loading = true;
    try {
      const user = this.authService.currentUserValue;
      if (!user) throw new Error('Utente non autenticato');

      const formValue = this.profileForm.value;

      const updateData = {
        phone: formValue.phone || null,
        address: formValue.address || null,
        province: formValue.province || null,
        updated_at: new Date().toISOString()
      };

      const { error } = await this.supabaseClient
        .from('users')
        .update(updateData)
        .eq('id', user.id);

      if (error) throw error;

      alert('Profilo aggiornato con successo!');
    } catch (err: any) {
      console.error('Errore salvataggio:', err);
      alert('Errore durante il salvataggio: ' + (err.message || 'Errore sconosciuto'));
    } finally {
      this.loading = false;
      this.cdRef.detectChanges();
    }
  }

  restartTutorial(): void {
    const context = this.authService.getCurrentContext();
    const type: TutorialType = context === 'staff' ? 'business' : 'customer';
    this.tutorialService.restartTutorial(type);
  }

  
}